document.addEventListener('DOMContentLoaded', () => {
    // --- Dark Mode Toggle ---
    const toggleButton = document.getElementById('dark-mode-toggle');
    const htmlElement = document.documentElement;

    function setTheme(theme) {
        if (theme === 'dark') {
            htmlElement.classList.add('dark-mode');
            localStorage.setItem('theme', 'dark');
        } else {
            htmlElement.classList.remove('dark-mode');
            localStorage.setItem('theme', 'light');
        }
    }

    function getPreferredTheme() {
        const storedTheme = localStorage.getItem('theme');
        if (storedTheme) {
            return storedTheme;
        }
        return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
    }

    setTheme(getPreferredTheme());

    if (toggleButton) {
        toggleButton.addEventListener('click', () => {
            const currentTheme = localStorage.getItem('theme');
            setTheme(currentTheme === 'dark' ? 'light' : 'dark');
        });
    }

    // --- Archive Page Sidebar Link Handler ---
    function handleArchiveLinks() {
        const archiveLinks = document.querySelectorAll('.sidebar .card a[href*="/archive/#"]');
        if (archiveLinks.length === 0) return;

        // Dynamically determine the correct, language-specific path for the archive JSON file
        // by looking at the first link found.
        const firstLinkHref = archiveLinks[0].getAttribute('href');
        const archivePagePath = firstLinkHref.substring(0, firstLinkHref.indexOf('#'));
        const jsonPath = `${archivePagePath}/archive-month.json`;

        // On page load, if there's a hash on an archive page, try to scroll to it.
        if (window.location.pathname.includes('/archive/') && window.location.hash) {
            const targetId = decodeURIComponent(window.location.hash.substring(1));
            setTimeout(() => {
                const targetElement = document.getElementById(targetId);
                if (targetElement) {
                    targetElement.scrollIntoView({ behavior: 'smooth', block: 'start' });
                }
            }, 100);
        }

        fetch(jsonPath) // Use the language-specific path
            .then(response => {
                if (!response.ok) throw new Error(`Failed to load ${jsonPath}`);
                return response.json();
            })
            .then(monthMap => {
                archiveLinks.forEach(link => {
                    link.addEventListener('click', function(event) {
                        const href = this.getAttribute('href');
                        const month = href.split('#')[1];

                        // Determine the base URL for the current language's archive from the link itself
                        const archiveBaseUrl = href.substring(0, href.indexOf('/archive/')) + '/archive/';

                        if (month && monthMap[month]) {
                            event.preventDefault(); // We have a custom navigation logic

                            const pageNum = monthMap[month];
                            let targetUrl = archiveBaseUrl;
                            if (pageNum > 1) {
                                targetUrl = `${archiveBaseUrl}page/${pageNum}/`;
                            }
                            
                            const finalUrl = targetUrl + '#' + month;

                            // If we are already on the destination URL, just scroll. Otherwise, navigate.
                            if (window.location.href.endsWith(finalUrl)) {
                                const targetElement = document.getElementById(month);
                                if (targetElement) {
                                    targetElement.scrollIntoView({ behavior: 'smooth', block: 'start' });
                                }
                            } else {
                                window.location.href = finalUrl;
                            }
                        }
                    });
                });
            })
            .catch(error => {
                console.error('Archive link handler failed:', error);
                // If this logic fails, the links will fall back to their default behavior.
            });
    }

    handleArchiveLinks();
});

;

document.addEventListener('DOMContentLoaded', function () {
    // Debounce function
    const debounce = (func, delay) => {
        let timeout;
        return function(...args) {
            const context = this;
            clearTimeout(timeout);
            timeout = setTimeout(() => func.apply(context, args), delay);
        };
    };

    const searchForm = document.getElementById('search-form');
    const searchInput = document.getElementById('search-input');
    const searchOverlay = document.getElementById('search-overlay');
    const searchResults = document.getElementById('search-results');
    const closeSearchBtn = document.getElementById('close-search');
    const navbarCloseBtn = document.getElementById('navbar-close-btn');

    if (navbarCloseBtn) {
        navbarCloseBtn.addEventListener('click', function (e) {
            e.preventDefault();
            const navbar = document.getElementById('main-navbar');
            if (navbar) navbar.style.display = 'none';
        });
    }

    let index;
    let documents = [];

    function loadFlexSearchLibrary() {
        return new Promise((resolve, reject) => {
            if (typeof FlexSearch !== 'undefined') {
                resolve();
                return;
            }
            const script = document.createElement('script');
            script.src = 'https://cdn.jsdelivr.net/npm/flexsearch@0.7.31/dist/flexsearch.bundle.js';
            script.onload = () => resolve();
            script.onerror = () => reject(new Error('Failed to load FlexSearch library'));
            document.head.appendChild(script);
        });
    }

    async function initializeFlexSearch() {
        try {
            await loadFlexSearchLibrary();

            const htmlTag = document.documentElement;
            const lang = htmlTag.lang;
            const defaultLang = 'zh'; // from hugo.toml

            const isDefaultLang = (lang === defaultLang);
            const defaultContentInSubdir = false; // from hugo.toml

            let indexPath;
            if (isDefaultLang && !defaultContentInSubdir) {
                indexPath = '/flexsearch.json';
            } else {
                indexPath = `/${lang}/flexsearch.json`;
            }

            const response = await fetch(indexPath);
            documents = await response.json();
            index = new FlexSearch.Document({
                document: {
                    id: "url",
                    index: ["title", "content"],
                    store: ["title", "excerpt", "url", "content"]
                },
                tokenize: "full"
            });
            documents.forEach(doc => index.add(doc));
            return true;
        } catch (error) {
            console.error('Failed to initialize FlexSearch:', error);
            return false;
        }
    }

    const navbarIcon = document.querySelector('.navbar-icon'); // Get the search icon

    if (searchInput) {
        let flexSearchInitialized = false;

        // Add event listener for the search icon
        if (navbarIcon) {
            navbarIcon.addEventListener('click', function() {
                const term = searchInput.value.trim();
                if (term.length > 0) {
                    performSearch(term); // Perform search on icon click
                } else {
                    // If input is empty, just show the overlay for user to type
                    searchOverlay.style.display = 'flex';
                }
                searchInput.focus(); // Always focus the input
            });
        }

        searchInput.addEventListener('focus', async function () {
            if (!flexSearchInitialized) {
                flexSearchInitialized = await initializeFlexSearch();
                if (!flexSearchInitialized) {
                    searchResults.innerHTML = `<p class='no-results'>${i18next.t('searchInitFailed')}</p>`;
                    searchOverlay.style.display = 'flex';
                    return;
                }
            }
        });

        const debouncedPerformSearch = debounce(performSearch, 300); // Debounce with 300ms

        searchInput.addEventListener('input', function (e) {
            const term = e.target.value.trim();
            if (term.length > 0) {
                debouncedPerformSearch(term);
            }
        });

        searchOverlay.addEventListener('click', function (e) {
            if (e.target === searchOverlay) {
                searchOverlay.style.display = 'none';
            }
        });

        if (closeSearchBtn) {
            closeSearchBtn.addEventListener('click', function (e) {
                e.preventDefault();
                searchOverlay.style.display = 'none';
            });
        }

        searchForm.addEventListener('submit', function (e) {
            e.preventDefault();
            const term = e.target.value.trim();
            if (term.length > 0) {
                performSearch(term); // No debounce on submit to ensure immediate search
            }
        });
    }

    function performSearch(term) {
        if (!index) return;
        const results = index.search(term, { limit: 6, enrich: true });
        displayResults(results[0] ? results[0].result : []);
        searchOverlay.style.display = 'flex';
    }

    function displayResults(results) {
        if (results.length === 0) {
            searchResults.innerHTML = `<p class='no-results'>${i18next.t('noResults')}</p>`;
            return;
        }

        const term = searchInput.value.trim();

        const html = results.map((result) => {
            const doc = result.doc;
            const url = new URL(doc.url, window.location.origin);
            const displayUrl = url.pathname;

            const title = highlight(doc.title, term);
            const excerptContent = doc.excerpt || createExcerpt(doc.content, term);
            const excerpt = highlight(excerptContent, term);

            return `
                <div class="search-result-item">
                    <h3><a href="${doc.url}">${title}</a></h3>
                    <p>${excerpt}</p>
                    <span class="search-result-url">${displayUrl}</span>
                </div>
            `;
        }).join('');

        searchResults.innerHTML = html;

        const links = searchResults.querySelectorAll('a');
        links.forEach(link => {
            link.addEventListener('click', () => {
                searchOverlay.style.display = 'none';
            });
        });
    }

    function createExcerpt(content, term, maxLength = 120) {
        if (!content) {
            return '';
        }

        const termIndex = content.toLowerCase().indexOf(term.toLowerCase());
        if (termIndex === -1) {
            return content.length > maxLength ? content.substring(0, maxLength) + '...' : content;
        }

        const start = Math.max(0, termIndex - Math.floor(maxLength / 2));
        const end = Math.min(content.length, termIndex + term.length + Math.floor(maxLength / 2));

        let excerpt = content.substring(start, end);
        if (start > 0) {
            excerpt = '...' + excerpt;
        }
        if (end < content.length) {
            excerpt = excerpt + '...';
        }

        return excerpt;
    }

    function highlight(text, term) {
        if (!text || !term) {
            return text;
        }
        const regex = new RegExp(`(${term})`, 'gi');
        return text.replace(regex, '<strong class="search-highlight">$1</strong>');
    }
});
